## 3. 类型定义设计（与后端对齐迭代1）

### 3.1 迭代1需要的核心类型

```typescript
// 用户信息
export interface User {
  id: number;
  userId: string;
  nickname: string;
  avatar: string;
  openid?: string;
  phone?: string;
  createdAt: string;
  updatedAt: string;
}

// 方法论配置
export interface MethodConfig {
  id: number;
  methodId: string;
  name: string;
  description: string;
  promptTemplate: string;
  outputTemplate: string;
  isActive: number;
  sortOrder: number;
  createdAt: string;
  updatedAt: string;
}

// API统一响应格式
export interface ApiResponse<T> {
  code: number;
  message: string;
  data: T;
}

// 分页响应
export interface PaginationResponse<T> {
  list: T[];
  total: number;
  page: number;
  pageSize: number;
}

// 微信扫码登录响应
export interface QrCodeLoginResponse {
