## 4. API请求封装设计（迭代1）

### 4.1 基础配置 - request.ts

```typescript
import axios from 'axios';
import { message } from 'antd';
import { logout } from '../store/authSlice';
import store from '../store';

const request = axios.create({
  baseURL: import.meta.env.VITE_API_BASE_URL,
  timeout: 30000, // 30秒超时
});

// 请求拦截器 - 自动添加Authorization
request.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// 响应拦截器 - 统一错误处理
request.interceptors.response.use(
  (response) => {
    const res = response.data;
    if (res.code !== 0) {
      message.error(res.message || '请求错误');
      // 401 - 未授权，清除token跳登录
      if (res.code === 401) {
        store.dispatch(logout());
        window.location.reload();
      }
      return Promise.reject(new Error(res.message || '请求错误'));
    }
    return Promise.resolve(res.data);
  },
  (error) => {
    message.error(error.message || '网络错误');
    return Promise.reject(error);
  }
);

export default request;
```

### 4.2 认证API - auth.ts

```typescript
import request from '../utils/request';
import { ApiResponse, LoginResult, User, QrCodeLoginResponse } from '../types';

// 获取微信扫码登录二维码
export function getWechatQrCode(): Promise<ApiResponse<QrCodeLoginResponse>> {
  return request.get('/auth/wechat-qrcode');
}

// 轮询查询扫码登录结果
export function checkQrLoginResult(sceneStr: string): Promise<ApiResponse<LoginResult>> {
  return request.get(`/auth/check-qr-result/${sceneStr}`);
}

// 手机号验证码登录
export function phoneLogin(phone: string, code: string): Promise<ApiResponse<LoginResult>> {
  return request.post('/auth/phone-login', { phone, code });
}

// 发送短信验证码
export function sendSmsCode(phone: string): Promise<ApiResponse<void>> {
  return request.post('/auth/send-sms', { phone });
}

// 获取当前用户信息
export function getCurrentUser(): Promise<ApiResponse<User>> {
  return request.get('/auth/me');
}

// 退出登录
export function logoutApi(): Promise<ApiResponse<void>> {
  return request.post('/auth/logout');
}
```

### 4.3 方法论配置API - method.ts

```typescript
import request from '../utils/request';
import { ApiResponse, MethodConfig, PaginationResponse } from '../types';

// 获取方法论列表（分页）
export function getMethodList(page: number = 1, pageSize: number = 10): 
  Promise<ApiResponse<PaginationResponse<MethodConfig>>> {
  return request.get('/methods', { params: { page, page_size: pageSize } });
}

// 获取方法论详情
export function getMethodDetail(id: number): Promise<ApiResponse<MethodConfig>> {
  return request.get(`/methods/${id}`);
}

// 新增方法论
export function createMethod(data: Partial<MethodConfig>): Promise<ApiResponse<MethodConfig>> {
  return request.post('/methods', data);
}

// 更新方法论
export function updateMethod(id: number, data: Partial<MethodConfig>): 
  Promise<ApiResponse<MethodConfig>> {
  return request.put(`/methods/${id}`, data);
}

// 启用/禁用方法论
export function toggleMethodStatus(id: number, isActive: number): 
  Promise<ApiResponse<void>> {
  return request.patch(`/methods/${id}/status`, { is_active: isActive });
}

// 删除方法论
export function deleteMethod(id: number): Promise<ApiResponse<void>> {
  return request.delete(`/methods/${id}`);
}

// 测试方法论模板
export function testMethodTemplate(id: number, question: string): 
  Promise<ApiResponse<{result: string}>> {
  return request.post(`/methods/${id}/test`, { question });
}
```

