## 5. 状态管理设计（迭代1 - authSlice）

```typescript
// src/store/authSlice.ts
import { createSlice, PayloadAction } from '@reduxjs/toolkit';
import { User } from '../types/models';

interface AuthState {
  token: string | null;
  user: User | null;
  loading: boolean;
}

const initialState: AuthState = {
  token: localStorage.getItem('token'),
  user: null,
  loading: false,
};

const authSlice = createSlice({
  name: 'auth',
  initialState,
  reducers: {
    setToken: (state, action: PayloadAction<string | null>) => {
      state.token = action.payload;
      if (action.payload) {
        localStorage.setItem('token', action.payload);
      } else {
        localStorage.removeItem('token');
      }
    },
    setUser: (state, action: PayloadAction<User | null>) => {
      state.user = action.payload;
    },
    setLoading: (state, action: PayloadAction<boolean>) => {
      state.loading = action.payload;
    },
    logout: (state) => {
      state.token = null;
      state.user = null;
      localStorage.removeItem('token');
    },
  },
});

export const { setToken, setUser, setLoading, logout } = authSlice.actions;
export default authSlice.reducer;
```

---

## 6. 路由设计与路由守卫

### 6.1 路由配置

```typescript
// src/router.tsx
import { createBrowserRouter, Navigate } from 'react-router-dom';
import App from './App';
import Login from './pages/Login';
import PersonalInfo from './pages/PersonalInfo';
import MethodConfig from './pages/MethodConfig';
import NotFound from './pages/NotFound';
import { authGuard } from './utils/authGuard';

const router = createBrowserRouter([
  {
    path: '/',
    element: <App />,
    children: [
      {
        index: true,
        element: <Navigate to="/login" replace />,
      },
      {
        path: 'login',
        element: <Login />,
      },
      {
        path: 'me',
        element: authGuard(PersonalInfo),
      },
      {
        path: 'admin/methods',
        element: authGuard(MethodConfig),
      },
      {
        path: '*',
        element: <NotFound />,
      },
    ],
  },
]);

export default router;
```

### 6.2 路由守卫实现

```typescript
// src/utils/authGuard.tsx
import { Navigate } from 'react-router-dom';
import { useSelector } from 'react-redux';
import { RootState } from '../store';

export function authGuard(Component: React.ComponentType) {
  return () => {
    const token = useSelector((state: RootState) => state.auth.token);
    if (!token) {
      return <Navigate to="/login" replace />;
    }
    return <Component />;
  };
}
```

**逻辑说明：**
- 所有需要认证的页面都包装在authGuard中
- 没有token自动跳转到登录页
- 满足验收标准："未登录访问任何页面都跳转登录"

